-        // Scalar tail: process remaining elements
+        // Scalar tail: branchless processing like main loop
         while (read_pos < len) {
             const left = ptr[read_pos];
-            const right = if (read_pos + 1 < len) ptr[read_pos + 1] else 0;
+            const has_right = read_pos + 1 < len;
